import { Text as PDFText, View } from '@react-pdf/renderer';
import type { Style } from '@react-pdf/types';
import { usePdfxTheme, useSafeMemo } from '../lib/pdfx-theme-context';
import { resolveColor } from '../../lib/resolve-color';
import { createWatermarkStyles } from './pdfx-watermark.styles';
import type { PdfWatermarkProps, WatermarkPosition } from './pdfx-watermark.types';

/**
 * PdfWatermark — Displays a diagonal or positioned text overlay on PDF pages.
 *
 * Common use cases include "DRAFT", "CONFIDENTIAL", "PAID", "VOID", "COPY", etc.
 * The watermark uses absolute positioning and appears behind content.
 * Use the `fixed` prop (default: true) to repeat on every page.
 *
 * @example Basic usage (diagonal "DRAFT" on every page)
 * ```tsx
 * <Page>
 *   <PdfWatermark text="DRAFT" />
 *   {content}
 * </Page>
 * ```
 *
 * @example Confidential document
 * ```tsx
 * <PdfWatermark text="CONFIDENTIAL" color="destructive" opacity={0.1} />
 * ```
 *
 * @example Paid invoice stamp (no rotation)
 * ```tsx
 * <PdfWatermark text="PAID" angle={0} color="success" fontSize={80} />
 * ```
 *
 * @example Corner watermark
 * ```tsx
 * <PdfWatermark text="COPY" position="top-right" angle={0} fontSize={24} />
 * ```
 */
const THEME_COLOR_KEYS = ['foreground','muted','mutedForeground','primary','primaryForeground','accent','destructive','success','warning','info'] as const;
function resolveColor(value: string, colors: Record<string, string>): string {
  return THEME_COLOR_KEYS.includes(value as (typeof THEME_COLOR_KEYS)[number]) ? colors[value] : value;
}

export function PdfWatermark({
  text,
  opacity = 0.15,
  fontSize = 60,
  color = 'mutedForeground',
  angle = -45,
  position = 'center',
  fixed = true,
  style,
}: PdfWatermarkProps) {
  const theme = usePdfxTheme();
  const styles = useSafeMemo(() => createWatermarkStyles(theme), [theme]);

  const positionMap: Record<WatermarkPosition, Style> = {
    center: styles.positionCenter,
    'top-left': styles.positionTopLeft,
    'top-right': styles.positionTopRight,
    'bottom-left': styles.positionBottomLeft,
    'bottom-right': styles.positionBottomRight,
  };

  const containerStyles: Style[] = [styles.container, positionMap[position]];

  if (style) {
    containerStyles.push(style);
  }

  const resolvedColor = resolveColor(color, theme.colors);

  const textStyles: Style[] = [
    styles.text,
    {
      fontSize,
      color: resolvedColor,
      opacity,
      transform: `rotate(${angle}deg)`,
    },
  ];

  return (
    <View style={containerStyles} fixed={fixed}>
      <PDFText style={textStyles}>{text}</PDFText>
    </View>
  );
}

import { StyleSheet } from '@react-pdf/renderer';
import { usePdfxTheme } from '../lib/pdfx-theme-context';
type PdfxTheme = ReturnType<typeof usePdfxTheme>;

export function createWatermarkStyles(theme: PdfxTheme) {
  const { typography } = theme;

  return StyleSheet.create({
    container: {
      position: 'absolute',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      justifyContent: 'center',
      alignItems: 'center',
      zIndex: -1,
      pointerEvents: 'none',
    },
    text: {
      fontFamily: typography.heading.fontFamily,
      fontWeight: 700,
      textTransform: 'uppercase',
      letterSpacing: 4,
    },
    // Position variants
    positionCenter: {
      justifyContent: 'center',
      alignItems: 'center',
    },
    positionTopLeft: {
      justifyContent: 'flex-start',
      alignItems: 'flex-start',
      paddingTop: 100,
      paddingLeft: 50,
    },
    positionTopRight: {
      justifyContent: 'flex-start',
      alignItems: 'flex-end',
      paddingTop: 100,
      paddingRight: 50,
    },
    positionBottomLeft: {
      justifyContent: 'flex-end',
      alignItems: 'flex-start',
      paddingBottom: 100,
      paddingLeft: 50,
    },
    positionBottomRight: {
      justifyContent: 'flex-end',
      alignItems: 'flex-end',
      paddingBottom: 100,
      paddingRight: 50,
    },
  });
}

/**
 * Position preset for the watermark.
 */
export type WatermarkPosition =
  | 'center'
  | 'top-left'
  | 'top-right'
  | 'bottom-left'
  | 'bottom-right';

/**
 * Props for the PdfWatermark component.
 */
export interface PdfWatermarkProps {
  /** Custom styles to merge with component defaults */
  style?: Style;
  /**
   * The text to display as a watermark.
   * Common values: "DRAFT", "CONFIDENTIAL", "PAID", "VOID", "COPY", "SAMPLE"
   */
  text: string;

  /**
   * Opacity of the watermark (0 to 1).
   * @default 0.15
   */
  opacity?: number;

  /**
   * Font size in PDF points.
   * @default 60
   */
  fontSize?: number;

  /**
   * Color of the watermark text.
   * Can be a hex color or theme color key (e.g., "primary", "destructive").
   * @default "mutedForeground"
   */
  color?: string;

  /**
   * Rotation angle in degrees.
   * Use negative values for counter-clockwise rotation.
   * @default -45
   */
  angle?: number;

  /**
   * Position of the watermark on the page.
   * @default "center"
   */
  position?: WatermarkPosition;

  /**
   * Whether the watermark should be fixed (appear on every page).
   * @default true
   */
  fixed?: boolean;

  /**
   * No children allowed.
   */
  children?: never;
}
